<?php header('Content-Type: application/json'); require __DIR__.'/_config.php'; $raw=file_get_contents('php://input'); $d=json_decode($raw,true)?:[]; $name=trim($d['name']??''); $stars=max(1,min(5,intval($d['stars']??5))); $content=trim($d['content']??''); if(strlen($name)<2||strlen($content)<10){http_response_code(400);echo json_encode(['ok'=>false]);exit;} $stmt=$mysqli->prepare('INSERT INTO reviews(name,stars,content,status) VALUES (?,?,?,"pending")'); $stmt->bind_param('sis',$name,$stars,$content); echo $stmt->execute()?json_encode(['ok'=>true,'pending'=>true]):(http_response_code(500) or json_encode(['ok'=>false])); ?>